diff --git a/back_end/app/api/v1/endpoints/notifications.py b/back_end/app/api/v1/endpoints/notifications.py
index b50d1d3..ca64ba1 100644
--- a/back_end/app/api/v1/endpoints/notifications.py
+++ b/back_end/app/api/v1/endpoints/notifications.py
@@ -143,9 +143,13 @@ async def websocket_endpoint(websocket: WebSocket, user_id: str):
     try:
         while True:
             data = await websocket.receive_text()
+            if data == "ping":
+                await websocket.send_text("pong")

     except WebSocketDisconnect:
         manager.disconnect(websocket, user_id)
+    except Exception:
+        manager.disconnect(websocket, user_id)


