diff --git a/docker/nginx/nginx.conf b/docker/nginx/nginx.conf
index b63043a..5407162 100644
--- a/docker/nginx/nginx.conf
+++ b/docker/nginx/nginx.conf
@@ -49,7 +49,7 @@ http {
     add_header X-Content-Type-Options nosniff;
     add_header X-XSS-Protection "1; mode=block";
     add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;
-    add_header Content-Security-Policy "default-src 'self'; script-src 'self' 'unsafe-inline' 'unsafe-eval'; style-src 'self' 'unsafe-inline'; img-src 'self' data: https:; font-src 'self' https:; connect-src 'self' https:; frame-ancestors 'self';";
+    add_header Content-Security-Policy "default-src 'self'; script-src 'self' 'unsafe-inline' 'unsafe-eval'; style-src 'self' 'unsafe-inline'; img-src 'self' data: https:; font-src 'self' https:; connect-src 'self' https: ws: wss:; frame-ancestors 'self';";

     upstream patent_board_backend {
         server patent-board:8001;
@@ -76,6 +76,19 @@ http {
         # Security
         client_max_body_size 50M;

+        # WebSocket notifications (must be before general /api/ block)
+        location /api/v1/notifications/ws/ {
+            proxy_pass http://patent_board_backend;
+            proxy_http_version 1.1;
+            proxy_set_header Upgrade $http_upgrade;
+            proxy_set_header Connection "upgrade";
+            proxy_set_header Host $host;
+            proxy_set_header X-Real-IP $remote_addr;
+            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
+            proxy_read_timeout 86400s;
+            proxy_send_timeout 86400s;
+        }
+
         # API endpoints
         location /api/ {
             proxy_pass http://patent_board_backend;
@@ -83,12 +96,12 @@ http {
             proxy_set_header X-Real-IP $remote_addr;
             proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
             proxy_set_header X-Forwarded-Proto $scheme;
-            
+
             # Timeouts
             proxy_connect_timeout 60s;
             proxy_send_timeout 60s;
             proxy_read_timeout 60s;
-            
+
             # Rate limiting
             limit_req zone=addr burst=20 nodelay;
         }
diff --git a/front_end/src/context/NotificationsContext.jsx b/front_end/src/context/NotificationsContext.jsx
index 6f281ad..4b7715c 100644
--- a/front_end/src/context/NotificationsContext.jsx
+++ b/front_end/src/context/NotificationsContext.jsx
@@ -6,11 +6,18 @@ const NotificationsContext = createContext(null);
 const getWsBaseUrl = () => {
     const apiUrl = import.meta.env.VITE_API_URL;
     if (apiUrl && apiUrl.startsWith('http')) {
-        return apiUrl.replace(/^http/, 'ws');
+        // Extract only the origin (scheme + host), not the path
+        // e.g. http://host:48001/api/v1 → ws://host:48001
+        try {
+            const url = new URL(apiUrl);
+            return url.origin.replace(/^http/, 'ws');
+        } catch {
+            return apiUrl.replace(/^http/, 'ws');
+        }
     }
     // Fallback to current host for relative paths or production
     const protocol = window.location.protocol === 'https:' ? 'wss' : 'ws';
-    const host = window.location.host || 'localhost:8005';
+    const host = window.location.host || 'localhost:48001';
     return `${protocol}://${host}`;
 };

